import React, { useState } from 'react';
import Quiz from './components/Quiz';
import DataManager from './components/DataManager';
import { BrainCircuit, Database, Layout } from 'lucide-react';

function App() {
  const [activeTab, setActiveTab] = useState('quiz');

  return (
    <div className="min-h-screen bg-[#f7f7f7] font-sans text-slate-900">
      {/* Navbar Style Duolingo */}
      <nav className="bg-white border-b-2 border-slate-200 px-10 py-5 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="bg-green-500 p-2 rounded-lg rotate-3 shadow-md">
            <Database className="text-white" size={24} />
          </div>
          <h1 className="text-3xl font-black text-green-600 tracking-tighter">MONGOLINGO</h1>
        </div>
        
        <div className="flex gap-6">
          <button onClick={() => setActiveTab('quiz')} className={`flex items-center gap-2 font-bold uppercase tracking-wider ${activeTab === 'quiz' ? 'text-blue-500' : 'text-slate-400 hover:text-slate-600'}`}>
            <BrainCircuit size={20} /> Apprendre
          </button>
          <button onClick={() => setActiveTab('data')} className={`flex items-center gap-2 font-bold uppercase tracking-wider ${activeTab === 'data' ? 'text-blue-500' : 'text-slate-400 hover:text-slate-600'}`}>
            <Layout size={20} /> Lab & Data
          </button>
        </div>
      </nav>

      <main className="max-w-4xl mx-auto py-12 px-6">
        {activeTab === 'quiz' ? <Quiz /> : <DataManager />}
      </main>
    </div>
  );
}

export default App;
